import boto3
from botocore.exceptions import ClientError
import json

# Initialize SQS client
sqs = boto3.client('sqs')

def process_message(message):
    try:
        # Parse message body as JSON
        data = json.loads(message['Body'])
        
        # Determine action based on message type
        if 'type' in data and data['type'] == 'job':
            job_id = data['id']
            job_data = data.get('data', {})
            
            # Execute job processing logic here
            print(f"Processing job {job_id} with data: {job_data}")
        
        elif 'type' in data and data['type'] == 'error':
            error_data = data.get('data', {})
            # Handle error message processing logic here
            print(f"Error occurred: {error_data}")
        
    except json.JSONDecodeError:
        print("Invalid JSON format")
    
    except Exception as e:
        print(f"Error processing message: {e}")

def poll_sqs_queue(queue_url):
    try:
        response = sqs.receive_message(
            QueueUrl=queue_url,
            MaxNumberOfMessages=10,
            WaitTimeSeconds=20
        )
        
        if 'Messages' in response:
            for message in response['Messages']:
                process_message(message)
                
                # Delete processed message from SQS queue
                sqs.delete_message(QueueUrl=queue_url, ReceiptHandle=message['ReceiptHandle'])
    
    except ClientError as e:
        print(f"Error polling SQS queue: {e}")

def main():
    queue_url = 'https://sqs.us-east-1.amazonaws.com/123456789012/my-queue'
    poll_sqs_queue(queue_url)

if __name__ == "__main__":
    main()